  TrendingUp,
  Wallet,
  LayoutGrid,
  BarChart4,
  Edit2,
  Trash2,
  FileSpreadsheet,
  Settings2
} from 'lucide-react';
import * as XLSX from 'xlsx';

import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { useBudgetStore } from '@/store/use-budget-store';
import { useProjectStore } from '@/store/use-project-store';
import { ExpenditureDialog } from '@/components/expenditure-dialog';
import { CategoryManagementDialog } from '@/components/budget/category-management-dialog';
import { cn } from '@/lib/utils';
import { formatWithCommas } from '@/lib/number-format';
import { useSearchParams } from 'next/navigation';

import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

export default function BudgetPage() {
  return (
    <React.Suspense fallback={<div className="p-8 text-center text-slate-500 font-bold">濡쒕뵫 以?..</div>}>
      <BudgetPageContent />
    </React.Suspense>
  );
}

function BudgetPageContent() {
  const [mounted, setMounted] = React.useState(false);
  const searchParams = useSearchParams();
  const editId = searchParams.get('editId');

  const { 
    categories, 
    managements, 
    expenditures, 
    fetchBudgets,
    deleteExpenditure,
    activeProjectId,
    setActiveProjectId
  } = useBudgetStore();
  const { projects, fetchProjects, selectedLv1Ids } = useProjectStore();

  // ?ㅼ씠?쇰줈洹??곹깭
  const [expenditureDialogOpen, setExpenditureDialogOpen] = React.useState(false);
  const [categoryManagementOpen, setCategoryManagementOpen] = React.useState(false);
  const [editingExpenditure, setEditingExpenditure] = React.useState<any>(null);

  React.useEffect(() => {
    setMounted(true);
    fetchProjects();
    fetchBudgets();
  }, [fetchProjects, fetchBudgets]);

  // editId ?뚮씪誘명꽣 泥섎━
  React.useEffect(() => {
    if (mounted && editId && expenditures.length > 0) {
      const expenditure = expenditures.find(e => e.id === editId);
      if (expenditure) {
        const management = managements.find(m => m.id === expenditure.managementId);
        const category = management ? categories.find(c => c.id === management.categoryId) : null;
        const targetProjectId = category?.projectId;

        if (targetProjectId && targetProjectId !== activeProjectId) {
          setActiveProjectId(targetProjectId);
          fetchBudgets(targetProjectId || undefined);
        }
        setEditingExpenditure(expenditure);
        setExpenditureDialogOpen(true);
      }
    }
  }, [mounted, editId, expenditures, activeProjectId, setActiveProjectId, fetchBudgets]);

  // LV1 ?ъ뾽???꾪꽣留?n  const lv1Projects = projects.filter(p => p.level === 1);

  React.useEffect(() => {
    if (!mounted) return;
    if (lv1Projects.length > 0) {
      const isCurrentProjectValid = lv1Projects.some(p => p.id === activeProjectId);
      if (!isCurrentProjectValid) {
        const nextId = lv1Projects[0].id;
        setActiveProjectId(nextId);
        fetchBudgets(nextId || undefined);
      }
    }
  }, [mounted, selectedLv1Ids, lv1Projects, activeProjectId, setActiveProjectId, fetchBudgets]);

  if (!mounted) return null;

  const totalCatBudget = categories.reduce((sum, c) => sum + c.totalBudget, 0);
  const totalCatSpent = categories.reduce((sum, c) => sum + (c.totalExpenditure || 0), 0);

  const handleEditExpenditure = (exp: any) => {
    setEditingExpenditure(exp);
    setExpenditureDialogOpen(true);
  };

  const handleDeleteExpenditure = async (exp: any) => {
    const ok = window.confirm(`'${exp.subDetail}' 吏異??댁뿭????젣?섏떆寃좎뒿?덇퉴?\n泥⑤???利앸튃 ?뚯씪???④퍡 ??젣?⑸땲??`);
    if (ok) {
      try {
        await deleteExpenditure(exp.id, exp.attachmentName);
        alert('??젣?섏뿀?듬땲??');
      } catch (err) {
        console.error('Delete error:', err);
        alert('??젣 以??ㅻ쪟媛 諛쒖깮?덉뒿?덈떎.');
      }
    }
  };

  const handleExportExcel = () => {
    const excelData: any[] = [];
    categories.forEach(cat => {
      const catMans = managements.filter(m => m.categoryId === cat.id);
      catMans.forEach(man => {
        const manExps = expenditures.filter(exp => exp.managementId === man.id);
        const usageRate = ((man.totalExpenditure / (man.budgetAmount || 1)) * 100).toFixed(1) + '%';
        if (manExps.length === 0) {
          excelData.push({
            '鍮꾨ぉ(LV1)': cat.name, '愿由ъ꽭紐?LV2)': man.name, '?몄꽭紐?LV3)': '-',
            '諛곗젙?덉궛': man.budgetAmount, '吏묓뻾??: 0, '吏묓뻾?붿븸': man.balance, '?ъ슜??: usageRate
          });
        } else {
          manExps.forEach(exp => {
            excelData.push({
              '鍮꾨ぉ(LV1)': cat.name, '愿由ъ꽭紐?LV2)': man.name, '?몄꽭紐?LV3)': exp.subDetail,
              '諛곗젙?덉궛': man.budgetAmount, '吏묓뻾??: exp.amount, '吏묓뻾?붿븸': man.balance, '?ъ슜??: usageRate
            });
          });
        }
      });
    });
    const worksheet = XLSX.utils.json_to_sheet(excelData);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "?뺤궛?곗씠?고쁽??

'use client';

import * as React from 'react';
import FullCalendar from '@fullcalendar/react';
import dayGridPlugin from '@fullcalendar/daygrid';
import timeGridPlugin from '@fullcalendar/timegrid';
import interactionPlugin from '@fullcalendar/interaction';

import { format } from 'date-fns';
import { Calendar as CalendarIcon, Clock, FileDown } from 'lucide-react';
import { cn } from '@/lib/utils';
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import { Button } from '@/components/ui/button';

export interface CalendarEvent {
  id: string;
  title: string;
  start: string;
  end: string;
  allDay?: boolean;
  backgroundColor?: string;
  borderColor?: string;
  textColor?: string;
  extendedProps: {
    type: 'project' | 'meeting' | 'budget';
    color?: { bg: string; text: string; border: string };
    isPeriod?: boolean;
    partner?: string;
    partnerFull?: string;
    projectFull?: string;
    programName?: string;
    location?: string;
    capacity?: number;
    attendance?: number;
    sessionNum?: number;
    meetingTitle?: string;
    category?: string;
    managementName?: string;
    subDetail?: string;
    vendor?: string;
    amount?: number;
    editId?: string;
  };
}

import { HOLIDAYS_2026 as HOLIDAYS } from './holidays';

interface CalendarViewProps {
  events: CalendarEvent[];
  onEventClick?: (id: string, type: string) => void;
}

export default function CalendarView({ events, onEventClick }: CalendarViewProps) {
  const calendarRef = React.useRef<any>(null);

  const handleEventClick = (info: any) => {
    const { editId, type } = info.event.extendedProps;
    if (editId && onEventClick) {
      onEventClick(editId, type);
    }
  };

  const extractCalendarText = () => {
    const calendarApi = calendarRef.current?.getApi();
    if (!calendarApi) return;

    const view = calendarApi.view;
    const start = view.activeStart;
    const end = view.activeEnd;

    // ?꾩옱 酉곗쓽 ?대깽?몃뱾 媛?몄삤湲?n    const currentEvents = calendarApi.getEvents();
    const visibleEvents = currentEvents.filter((event: any) => {
      const eventStart = event.start;
      if (!eventStart) return false;
      return eventStart >= start && eventStart < end;
    });

    let text = `[罹섎┛???쇱젙 異붿텧 - ${view.title}]\n\n`;

    // ?좎쭨蹂꾨줈 ?뺣젹
    const sortedEvents = [...visibleEvents].sort((a: any, b: any) => 
      (a.start?.getTime() || 0) - (b.start?.getTime() || 0)
    );

    let currentDate = "";
    sortedEvents.forEach((event: any) => {
      const eventDate = format(event.start, 'yyyy-MM-dd');
      const props = event.extendedProps;

      if (currentDate !== eventDate) {
        currentDate = eventDate;
        text += `\n# ${currentDate}\n`;
      }

      const timeStr = event.allDay ? "醫낆씪" : format(event.start, 'HH:mm');

      if (props.type === 'meeting') {
        text += `- [?뚯쓽] ${timeStr} | ${props.sessionNum}?뚯감 | ${props.location || '?μ냼誘몄젙'} | 二쇱젣: ${props.meetingTitle || '?놁쓬'}\n`;
      } else if (props.type === 'project') {
        text += `- [?ъ뾽] ${timeStr} | ${props.partner || '?묐젰?щ???} | ${props.programName} | ?뺤썝: ${props.capacity || 0}紐?| 李몄뿬: ${props.attendance || 0}紐?
`;
      } else if (props.type === 'budget') {
        text += `- [吏異? ${timeStr} | ${props.category} | ${props.managementName} | ${props.subDetail} | 吏異쒖쿂: ${props.vendor} | 湲덉븸: ${(props.amount || 0).toLocaleString()}??
`;
      }
    });

    // ?띿뒪???뚯씪濡????n    const blob = new Blob([text], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `calendar_export_${format(new Date(), 'yyyyMMdd_HHmm')}.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl border border-slate-200/60 overflow-hidden flex flex-col h-full relative">
      <div className="absolute top-4 right-20 z-10">
        <Button 
          variant="outline" 
          size="sm" 
          onClick={extractCalendarText}
          className="bg-white/80 backdrop-blur-sm border-slate-200 hover:bg-slate-50 text-slate-600 font-bold gap-2 shadow-sm"
        >
          <FileDown className="size-4" />
          ?쇱젙 ?띿뒪??異붿텧
        </Button>
      </div>
      <div className="flex-1 p-1">
        <FullCalendar
          ref={calendarRef}
          plugins={[dayGridPlugin, timeGridPlugin, interactionPlugin]}
          initialView="dayGridMonth"
          headerToolbar={{
            left: 'prev,next today',
            center: 'title',
            right: 'dayGridMonth,timeGridWeek,timeGridDay'
          }}
          events={events}
          locale="ko"
          dayMaxEvents={false}
          dayCellContent={(arg) => {
            const dateStr = format(arg.date, 'yyyy-MM-dd');
            const holidayName = HOLIDAYS[dateStr];
            const isSunday = arg.date.getDay() === 0;
            const isSaturday = arg.date.getDay() === 6;
            const isHoliday = !!holidayName;

            return (
              <div className={cn(
                "flex flex-col items-center justify-center min-h-[24px] w-full",
                isSunday || isHoliday ? "text-red-500" : isSaturday ? "text-blue-500" : "text-slate-600"
              )}>
                {isHoliday && <span className="text-[7px] font-black leading-none mb-0.5">{holidayName}</span>}
                <span className="text-[11px] font-bold">{arg.dayNumberText.replace('??, '')}</span>
              </div>
            );
          }}
          eventContent={(arg) => <EventWithTooltip arg={arg} />}
          eventClick={handleEventClick}
          eventClassNames={(arg) => {
            const type = arg.event.extendedProps.type;
            const isPeriod = arg.event.extendedProps.isPeriod;
            return [
              'premium-event',
              `event-type-${type}`,
              isPeriod ? 'event-period' : 'event-point'
            ];
          }}
          eventDidMount={(info) => {
            const props = info.event.extendedProps;
            if (props.color) {
              if (props.isPeriod) {
                // ?댁쁺 ?쇱젙 ?꾩슜 ?ㅽ???(?뱀깋 ?뚮쭏 媛뺤젣: ?고븳 諛뷀깢 + ?뱀깋 ?뚮몢由?
                info.el.style.setProperty('background-color', '#f0fdf4', 'important'); 
                info.el.style.setProperty('border', '2px solid #22c55e', 'important');
                info.el.style.setProperty('color', '#166534', 'important');
                info.el.style.setProperty('border-radius', '4px', 'important');
              } else {
                // ?쇰컲 ?쇱젙: ?뚯깋/?щ젅?댄듃 ?뚮쭏 (getProjectColor?먯꽌 ?꾨떖??媛??ъ슜)
                info.el.style.setProperty('background-color', props.color.bg, 'important');
                info.el.style.setProperty('border', `1px solid ${props.color.border}`, 'important');
                info.el.style.setProperty('color', props.color.text, 'important');
              }
            }
          }}
          slotMinTime="08:00:00"
          slotMaxTime="22:00:00"
          allDaySlot={true}
          expandRows={true}
          handleWindowResize={true}
        />
      </div>

      <style jsx global>{`
        .fc {
          --fc-border-color: #f1f5f9;
          --fc-today-bg-color: #f8fafc;
          --fc-page-bg-color: #ffffff;
          font-family: inherit;
        }
        .fc .fc-col-header-cell {
          padding: 8px 0;
          background: #f8fafc;
        }
        .fc .fc-col-header-cell-cushion {
          font-size: 10px;
          font-weight: 800;
          color: #64748b;
          text-transform: uppercase;
          letter-spacing: 0.05em;
          text-decoration: none !important;
        }
        .fc .fc-daygrid-day-number {
          font-size: 10px;
          font-weight: 700;
          color: #94a3b8;
          padding: 6px 10px;
          text-decoration: none !important;
        }
        .fc .fc-day-today .fc-daygrid-day-number {
          color: #0f172a;
          font-weight: 900;
        }
        .fc-theme-standard td, .fc-theme-standard th {
          border: 1px solid #f1f5f9;
        }
        .fc .fc-scrollgrid {
          border: none;
        }

        /* premium-event start */
        .premium-event {
          padding: 0 !important;
          margin: 2px 0 !important;
          border: none !important;
          background: transparent !important;
        }

        .event-inner {
          padding: 4px 8px;
          font-size: 10px;
          font-weight: 800;
          white-space: nowrap;
          overflow: hidden;
          text-overflow: ellipsis;
          display: flex;
          align-items: center;
          gap: 6px;
          line-height: 1.4;
          width: 100%;
          min-width: 0;
          border-radius: 4px;
        }

        /* 湲곌컙 諛?Bar) ?뱁솕 ?ㅽ??? ?고븳 諛곌꼍 + ?뱀깋 ?뚮몢由?*/
        .event-period {
          z-index: 10 !important;
          min-height: 28px !important;
        }

        .event-period .event-inner {
          font-weight: 900;
          letter-spacing: -0.01em;
          box-shadow: 0 1px 2px rgba(0,0,0,0.05);
        }

        /* FullCalendar ?대? ?덉씠?꾩썐 蹂댁젙 */
        .fc-event-main, .fc-event-main-frame {
          width: 100% !important;
          height: 100% !important;
          display: flex !important;
        }

        .fc-daygrid-event {
          border-radius: 4px !important;
        }

        /* 二쇰쭚 ?됱긽 媛뺤젣 ?곸슜 */
        .fc-day-sun .fc-col-header-cell-cushion { color: #ef4444 !important; }
        .fc-day-sat .fc-col-header-cell-cushion { color: #3b82f6 !important; }
        .fc-daygrid-day.fc-day-sun .fc-daygrid-day-number { color: #ef4444 !important; }
        .fc-daygrid-day.fc-day-sat .fc-daygrid-day-number { color: #3b82f6 !important; }

        /* 怨듯쑕??紐낆묶 ?ㅽ???*/
        .holiday-label {
          font-size: 7px;
          font-weight: 900;
          color: #ef4444;
          margin-bottom: 1px;
        }
      `}</style>
    </div>
  );
}

function EventWithTooltip({ arg }: { arg: any }) {
  const type = arg.event.extendedProps.type;
  const props = arg.event.extendedProps;

  const timeStr = arg.event.allDay ? "醫낆씪" : format(arg.event.start, 'HH:mm');
  const dateStr = format(arg.event.start, 'yyyy-MM-dd');
  const displayTime = `${dateStr} ${timeStr}`;

  const tooltipContent = (
    <div className="space-y-1 p-1">
      <p className="text-[11px] font-black text-slate-900 border-b border-slate-100 pb-1 mb-1">
        {type === 'project' ? '?ъ뾽 ?곸꽭 ?뺣낫' : type === 'meeting' ? '?뚯쓽 ?곸꽭 ?뺣낫' : '吏異??곸꽭 ?뺣낫'}
      </p>
      {type === 'project' && (
        <>
          <p className="text-[10px] font-bold"><span className="text-slate-400">?쇱떆:</span> {displayTime}</p>
          <p className="text-[10px] font-bold"><span className="text-slate-400">?묐젰?낆껜紐?</span> {props.partnerFull}</p>
          <p className="text-[10px] font-bold"><span className="text-slate-400">?꾨줈洹몃옩紐?</span> {props.programName}</p>
          <p className="text-[10px] font-bold"><span className="text-slate-400">?뺤썝:</span> {props.capacity || 0}紐?/p>
          <p className="text-[10px] font-bold"><span className="text-slate-400">李멸??몄썝:</span> {props.attendance || 0}紐?/p>
        </>
      )}
      {type === 'meeting' && (
        <>
          <p className="text-[10px] font-bold"><span className="text-slate-400">?쇱떆:</span> {displayTime}</p>
          <p className="text-[10px] font-bold"><span className="text-slate-400">?뚯감:</span> {props.sessionNum}?뚯감</p>
          <p className="text-[10px] font-bold"><span className="text-slate-400">?μ냼:</span> {props.location || '誘몄???}</p>
          <p className="text-[10px] font-bold"><span className="text-slate-400">?뚯쓽二쇱젣:</span> {props.meetingTitle || '?놁쓬'}</p>
        </>
      )}
      {type === 'budget' && (
        <>
          <p className="text-[10px] font-bold"><span className="text-slate-400">?쇱떆:</span> {displayTime}</p>
          <p className="text-[10px] font-bold"><span className="text-slate-400">鍮꾨ぉ:</span> {props.category}</p>
          <p className="text-[10px] font-bold"><span className="text-slate-400">愿由ъ꽭紐?</span> {props.managementName}</p>
          <p className="text-[10px] font-bold"><span className="text-slate-400">?몄꽭紐?</span> {props.subDetail}</p>
          <p className="text-[10px] font-bold"><span className="text-slate-400">吏異쒖쿂:</span> {props.vendor}</p>
          <p className="text-[10px] font-bold"><span className="text-slate-400">湲덉븸:</span> {(props.amount || 0).toLocaleString()}??/p>
        </>
      )}
    </div>
  );

  return (
    <TooltipProvider>
      <Tooltip>
        <TooltipTrigger className="w-full">
          <div className="event-inner w-full cursor-pointer">
            {type === 'project' && <CalendarIcon className="size-3 shrink-0" />}
            {type === 'meeting' && <Clock className="size-3 shrink-0" />}
            {type === 'budget' && <span className="text-[10px] font-bold shrink-0">??/span>}
            <span className="truncate">{arg.event.title}</span>
          </div>
        </TooltipTrigger>
        <TooltipContent side="top" className="bg-white/95 backdrop-blur shadow-2xl border-slate-200 rounded-xl p-3 min-w-[200px] z-[9999]">
          {tooltipContent}
        </TooltipContent>
      </Tooltip>
    </TooltipProvider>
  );
}

