            } else if (p.startDate) {
              // [?댁쁺] 諛붽? ?대? ?쒖떆??寃쎌슦 ?⑥씪 ?쇱젙? 以묐났?대?濡??쒖쇅
              if (isPeriodProject) return;

              // ?ъ뾽?쇱젙 ?⑥씪 異쒕젰 ?щ㎎ ?곸슜
              const singleTitle = getOptimalTitle(lv2NameAbbr, partnerNameAbbr, p.name);

              const pColor = getProjectColor(p.id);
