      <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm space-y-4">
        {/* ?꾪꽣 洹몃━??(LV1 ???쒓굅) */}
        <div className="border border-slate-100 rounded-xl overflow-hidden bg-slate-50/30">
