  const getPartnerProjects = (partnerId: string) => {
    // ?ㅼ떆媛꾩쑝濡??꾨줈?앺듃 ?곗씠?곕? 吏묎퀎?섏뿬 理쒖떊 ?곹깭 ?좎? (?몄뀡 諛??섏쐞 ?꾨줈?앺듃 諛섏쁺)
    const partnerProjects = projects
      .filter(p => p.partnerId === partnerId)
