'use client';

import * as React from 'react';
import { 
  X, 
  Plus, 
  Trash2,
  RefreshCw,
  Info,
  Maximize2,
  Minimize2
} from 'lucide-react';

import { 
  Dialog, 
  DialogContent, 
  DialogHeader, 
  DialogTitle,
  DialogFooter
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { usePartnerStore, PartnerDocument } from '@/store/use-partner-store';
import { Project } from '@/store/use-project-store';
import { FileUploadZone } from './file-upload-zone';
import { Separator } from '@/components/ui/separator';
import { uploadFileToStorage, generateStoragePath } from '@/lib/storage';
import { cn } from '@/lib/utils';

interface PartnerDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  project?: Project;
  mode?: 'add' | 'edit';
  partnerId?: string;
}

// ?덉쟾??ID ?앹꽦 ?ы띁
const generateSafeId = () => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) {
    return crypto.randomUUID();
  }
  return Math.random().toString(36).substring(2) + Date.now().toString(36);
};

export function PartnerDialog({ open, onOpenChange, project, mode = 'add', partnerId }: PartnerDialogProps) {
  const { partners, addPartner, updatePartner } = usePartnerStore();

  const [name, setName] = React.useState('');
  const [abbreviation, setAbbreviation] = React.useState('');
  const [manager, setManager] = React.useState('');
  const [phone1, setPhone1] = React.useState('');
  const [phone2, setPhone2] = React.useState('');
  const [email, setEmail] = React.useState('');
  const [address, setAddress] = React.useState('');
  const [isSubmitting, setIsSubmitting] = React.useState(false);
  const [isMaximized, setIsMaximized] = React.useState(false);

  // 媛蹂 怨꾩빟??由ъ뒪??n  const [contracts, setContracts] = React.useState<{id: string, name: string, originalName?: string, fileUrl?: string, file?: File}[]>([{ id: 'c1', name: '' }]);

  // 利앸튃 ?쒕쪟 ?곹깭 愿由?n  const [docs, setDocs] = React.useState<Record<string, { originalName: string, fileName: string, fileUrl: string, file?: File }>>({});

  // 珥덇린???⑥닔
  const resetForm = React.useCallback(() => {
    setName('');
    setAbbreviation('');
    setManager('');
    setPhone1('');
    setPhone2('');
    setEmail('');
    setAddress('');
    setDocs({});
    setContracts([{ id: 'c1', name: '' }]);
  }, []);

  // 珥덇린 ?곗씠???명똿
  React.useEffect(() => {
    if (open) {
      if (mode === 'edit' && partnerId) {
        const p = partners.find(item => item.id === partnerId);
        if (p) {
          setName(p.name);
          setAbbreviation(p.abbreviation || '');
          setManager(p.manager);
          setPhone1(p.phone1);
          setPhone2(p.phone2);
          setEmail(p.email);
          setAddress(p.address);

          const docMap: Record<string, { originalName: string, fileName: string, fileUrl: string }> = {};
          const contractList: {id: string, name: string, originalName?: string, fileUrl?: string}[] = [];
          p.documents.forEach(d => {
            if (d.type.includes('怨꾩빟??)) {
              contractList.push({ id: d.id, name: d.fileName, originalName: d.originalName, fileUrl: d.fileUrl });
            } else {
              docMap[d.type] = { originalName: d.originalName, fileName: d.fileName, fileUrl: d.fileUrl || '' };
            }
          });
          setDocs(docMap);
          setContracts(contractList.length > 0 ? contractList : [{ id: 'c1', name: '' }]);
        }
      }
    }
  }, [open, mode, partnerId, project, partners, resetForm]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) { alert('?낆껜紐낆쓣 ?낅젰?댁＜?몄슂.'); return; }

    setIsSubmitting(true);
    try {
      // 湲곗〈 臾몄꽌??以?怨꾩빟?쒓? ?꾨땶 寃껊뱾 蹂닿?
      const partner = partners.find(p => p.id === partnerId);
      const existingOtherDocs = partner ? partner.documents.filter(d => 
        !['?ъ뾽?먮벑濡앹쬆', '?듭옣?щ낯', '蹂댄뿕利앷텒', '?ъ쟾?먭?泥댄겕由ъ뒪??].includes(d.type) && 
        !d.type.includes('怨꾩빟??)
      ) : [];

      const combinedDocs: PartnerDocument[] = [...existingOtherDocs];

      // 1. 怨듯넻 利앸튃 ?쒕쪟 ?낅줈??泥섎━
      const commonTypes = ['?ъ뾽?먮벑濡앹쬆', '?듭옣?щ낯', '蹂댄뿕利앷텒', '?ъ쟾?먭?泥댄겕由ъ뒪??];
      for (const type of commonTypes) {
        const info = docs[type];
        if (!info) continue;

        let finalUrl = info.fileUrl;
        let storagePath = info.fileName;

        // ?덈줈 ?좏깮???뚯씪???덈뒗 寃쎌슦?먮쭔 ?대씪?곕뱶 ?낅줈???섑뻾
        if (info.file) {
          storagePath = generateStoragePath('partners', info.fileName);
          finalUrl = await uploadFileToStorage('partner-documents', storagePath, info.file);
        }

        if (finalUrl) {
          // [以묒슂] 留뚯빟 ?낅줈?쒕? 嫄곗튂吏 ?딆븘 ?ъ쟾??Base64(data:) ?뺥깭?쇰㈃ ?곗씠?곕쿋?댁뒪 ??μ쓣 李⑤떒
          if (finalUrl.startsWith('data:')) {
            throw new Error(`${type} ?뚯씪 ?낅줈?쒖뿉 ?ㅽ뙣?덉뒿?덈떎. ?ㅼ떆 ?쒕룄??二쇱꽭??`);
          }

          combinedDocs.push({
            id: generateSafeId(),
            type,
            originalName: info.originalName,
            fileName: storagePath,
            fileUrl: finalUrl
          });
        }
      }

      // 2. 怨꾩빟??諛?湲고? ?쒕쪟 ?낅줈??泥섎━
      for (let i = 0; i < contracts.length; i++) {
        const c = contracts[i];
        if (c.name) {
          let finalUrl = c.fileUrl;
          let storagePath = c.name;

          if (c.file) {
            storagePath = generateStoragePath('partners', c.name);
            finalUrl = await uploadFileToStorage('partner-documents', storagePath, c.file);
          }

          if (finalUrl) {
            // [以묒슂] 留뚯빟 ?낅줈?쒕? 嫄곗튂吏 ?딆븘 ?ъ쟾??Base64(data:) ?뺥깭?쇰㈃ ?곗씠?곕쿋?댁뒪 ??μ쓣 李⑤떒
            if (finalUrl.startsWith('data:')) {
              throw new Error(`${i+1}?뚯감 怨꾩빟???뚯씪 ?낅줈?쒖뿉 ?ㅽ뙣?덉뒿?덈떎. ?ㅼ떆 ?쒕룄??二쇱꽭??`);
            }

            combinedDocs.push({
              id: c.id || generateSafeId(),
              type: `${i+1}?뚯감 怨꾩빟??,
              originalName: c.originalName || c.name,
              fileName: storagePath,
              fileUrl: finalUrl
            });
          }
        }
      }

      const partnerData = {
        name,
        abbreviation,
        manager,
        phone1,
        phone2,
        email,
        address,
        documents: combinedDocs,
      };

      if (mode === 'add') {
        await addPartner(partnerData);
      } else if (mode === 'edit' && partnerId) {
        await updatePartner(partnerId, partnerData);
      }

      onOpenChange(false);
    } catch (err: any) {
      console.error('Submit error:', err);
      // 援ъ껜?곸씤 ?먮윭 硫붿떆吏 ?쒓났
      const errorMsg = err?.message || '?????녿뒗 ?ㅻ쪟';
      if (errorMsg.includes('storage') || errorMsg.includes('upload')) {
        alert(`?뚯씪 ?낅줈??以??ㅻ쪟媛 諛쒖깮?덉뒿?덈떎. ??μ냼(Bucket) 沅뚰븳?대굹 ?ㅽ듃?뚰겕瑜??뺤씤?댁＜?몄슂.\n(?먮윭: ${errorMsg})`);
      } else {
        alert(`?곗씠?????以??ㅻ쪟媛 諛쒖깮?덉뒿?덈떎: ${errorMsg}`);
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className={cn(
        "p-0 overflow-hidden rounded-[2rem] border-none shadow-2xl transition-all duration-300",
        isMaximized ? "max-w-[1700px] w-[98vw] h-[95vh]" : "max-w-[95vw] md:max-w-4xl lg:max-w-5xl"
      )}>
        <DialogHeader className="bg-slate-900 p-8 text-white relative">
           <DialogTitle className="text-2xl font-black">
             {mode === 'add' ? '?묐젰?낆껜 ?좉퇋 ?깅줉' : '?묐젰?낆껜 ?뺣낫 ?섏젙'}
           </DialogTitle>
           <p className="text-xs font-bold text-slate-400 mt-1 uppercase tracking-widest">
             Global Partner Registry & Compliance
           </p>
            <div className="absolute top-8 right-8 flex items-center gap-2">
              <Button
                variant="ghost"
                size="icon"
                onClick={() => setIsMaximized(!isMaximized)}
                className="text-slate-400 hover:text-white"
              >
                {isMaximized ? <Minimize2 className="size-5" /> : <Maximize2 className="size-5" />}
              </Button>
              <button 
                onClick={() => onOpenChange(false)}
                className="text-slate-400 hover:text-white transition-colors"
              >
                <X className="size-6" />
              </button>
            </div>
        </DialogHeader>

        <form onSubmit={handleSubmit} className={cn(
          "p-10 space-y-10 overflow-y-auto custom-scrollbar bg-slate-50/50",
          isMaximized ? "h-[calc(95vh-160px)]" : "max-h-[75vh]"
        )}>
          <section className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              <div className="md:col-span-2 grid gap-2.5">
                <Label className="text-xs font-black text-blue-600 ml-1 uppercase">?낆껜紐?<span className="text-red-500">*</span></Label>
                <Input 
                  placeholder="?곹샇紐??낆껜紐????낅젰?섏꽭??

h-14 px-6 rounded-2xl bg-white border-slate-200" 
              />
            </div>
          </section>

          <Separator className="bg-slate-200/60" />

          <section className="space-y-6">
              <div className="flex items-center gap-2 border-l-4 border-blue-600 pl-3">
                <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">怨듯넻 利앸튃 ?쒕쪟</h3>
              </div>

              {/* ?덈궡 媛?대뱶 ?뱀뀡 異붽? */}
              <div className="bg-blue-50/50 border border-blue-100 rounded-3xl p-6 space-y-4">
                <div className="flex items-center gap-2 text-blue-600 mb-2">
                  <Info className="size-4" />
                  <span className="text-[10px] font-black uppercase tracking-widest">利앸튃 ?쒕쪟 ?쒖텧 媛?대뱶</span>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-x-10 gap-y-3">
                  {[
                    { label: '?ъ뾽?먮벑濡앹쬆', desc: '?뚰듃?덉궗???곹샇, ??쒖옄, ?낇깭 諛?醫낅ぉ ?뺤씤???꾪븳 ?꾩닔 ?쒕쪟?낅땲??' },
                    { label: '?듭옣?щ낯', desc: '?뺤궛 ?湲?寃곗젣瑜??꾪븳 怨꾩쥖 ?뺣낫 ?뺤씤?⑹쑝濡??ъ슜?⑸땲??' },
                    { label: '蹂댄뿕利앷텒', desc: '?곸뾽諛곗긽梨낆엫 諛??ш퀬 蹂댁옣 踰붿쐞 ?뺤씤???꾪빐 ?꾩슂?⑸땲??' },
                    { label: '?ъ쟾?먭?泥댄겕由ъ뒪??, desc: '援먯쑁 ?쒖꽕 諛??명봽?쇱쓽 蹂댁븞/?덉쟾 ?먭? 寃곌낵瑜?湲곕줉???쒕쪟?낅땲??' },
                  ].map((guide, i) => (
                    <div key={i} className="flex gap-2 items-start">
                      <div className="size-1.5 rounded-full bg-blue-400 mt-1.5 shrink-0" />
                      <div>
                        <p className="text-[11px] font-black text-slate-700">{guide.label}</p>
                        <p className="text-[10px] font-medium text-slate-500 leading-relaxed">{guide.desc}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                {[
                  '?ъ뾽?먮벑濡앹쬆', '?듭옣?щ낯', '蹂댄뿕利앷텒', '?ъ쟾?먭?泥댄겕由ъ뒪??
                ].map(type => (
                  <FileUploadZone
                    key={type}
                    label={type}
                    value={docs[type] ? {
                      originalName: docs[type].originalName,
                      fileName: docs[type].fileName,
                      fileUrl: docs[type].fileUrl
                    } : null}
                    onRename={(originalName) => {
                      const extension = originalName.split('.').pop();
                      // ?꾨줈?앺듃媛 ?덉쑝硫??꾨줈?앺듃紐??ы븿, ?놁쑝硫??낆껜紐낅쭔
                      return `${project?.name || '怨듯넻'}_${name || '?낆껜'}_${type}.${extension}`;
                    }}
                    onChange={(fileInfo) => {
                      if (fileInfo) {
                        setDocs(prev => ({ ...prev, [type]: fileInfo }));
                      } else {
                        setDocs(prev => {
                          const next = { ...prev };
                          delete next[type];
                          return next;
                        });
                      }
                    }}
                  />
                ))}
             </div>
          </section>

          <section className="space-y-6">
             <div className="flex items-center justify-between border-l-4 border-slate-400 pl-3">
                <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">怨꾩빟??諛?湲고? ?쒕쪟</h3>
                <Button 
                  type="button" 
                  variant="ghost" 
                  size="sm" 
                  onClick={() => setContracts(prev => [...prev, { id: generateSafeId(), name: '' }])}
                  className="h-8 rounded-lg font-black text-[10px] text-blue-600 hover:bg-blue-50"
                >
                  <Plus className="size-3 mr-1" /> ?쒕쪟 ??ぉ 異붽?
                </Button>
             </div>

             <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                {contracts.map((c, i) => (
                   <div key={c.id} className="relative group/contract">
                      <FileUploadZone
                        label={c.id === 'c1' && i === 0 ? '湲곕낯 怨꾩빟?? : `異붽? ?쒕쪟 ${i+1}`}
                        value={c.name ? {
                          originalName: c.originalName || '',
                          fileName: c.name,
                          fileUrl: c.fileUrl
                        } : null}
                        onRename={(originalName) => {
                          const extension = originalName.split('.').pop();
                          return `${project?.name || '怨꾩빟'}_${name || '?낆껜'}_臾몄꽌${i+1}.${extension}`;
                        }}
                        onChange={(fileInfo) => {
                          const newList = [...contracts];
                          if (fileInfo) {
                            newList[i] = {
                              ...newList[i],
                              name: fileInfo.fileName,
                              originalName: fileInfo.originalName,
                              fileUrl: fileInfo.fileUrl,
                              file: fileInfo.file // [?섏젙] ?ㅼ젣 ?뚯씪 媛앹껜 蹂닿?
                            };
                          } else {
                            newList[i] = { ...newList[i], name: '', originalName: '', fileUrl: '', file: undefined };
                          }
                          setContracts(newList);
                        }}
                      />
                      {contracts.length > 1 && (
                        <button 
                          type="button"
                          onClick={() => setContracts(prev => prev.filter(item => item.id !== c.id))}
                          className="absolute top-8 -right-2 z-10 size-7 bg-red-100 text-red-600 rounded-full opacity-0 group-hover/contract:opacity-100 flex items-center justify-center transition-all shadow-md"
                        >
                           <Trash2 className="size-3.5" />
                        </button>
                      )}
                    </div>
                 ))}
              </div>
           </section>
         </form>

         <DialogFooter className="p-8 bg-white border-t border-slate-50 flex gap-3">
           <Button 
             type="button" 
             variant="ghost" 
             onClick={() => onOpenChange(false)}
             className="flex-1 h-16 rounded-2xl border-slate-100 text-slate-500 font-black"
           >
             痍⑥냼
           </Button>
           <Button 
             onClick={handleSubmit}
             disabled={isSubmitting}
             className="flex-[2] h-16 rounded-2xl bg-slate-900 text-white font-black shadow-2xl hover:bg-slate-800 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
           >
             {isSubmitting ? (
               <div className="flex items-center gap-2">
                 <RefreshCw className="size-5 animate-spin" />
                 <span>泥섎━ 以?..</span>
               </div>
             ) : (
               mode === 'add' ? '?낆껜 ?깅줉?섍린' : '?뺣낫 ?섏젙 ?꾨즺'
             )}
           </Button>
         </DialogFooter>
       </DialogContent>
     </Dialog>
  );
}

import { PDFDocument, rgb, PDFFont } from 'pdf-lib';
import { jsPDF } from 'jspdf';
import fontkit from '@pdf-lib/fontkit';

/**
 * 吏異?利앸튃 PDF 蹂묓빀 諛??명꽣 異붽? ?좏떥由ы떚
 */
export async function generateSettlementPDF(
  projectName: string, 
  executionName: string, 
  expenditures: any[]
) {
  try {
    // 2. pdf-lib???댁슜??蹂묓빀
    const mergedPdf = await PDFDocument.create();
    mergedPdf.registerFontkit(fontkit);

    // ?쒓? ?고듃 濡쒕뱶 (Google Fonts CDN ?ъ슜)
    const fontUrl = 'https://fonts.gstatic.com/s/nanumgothic/v23/PN_oTaWLYAdPhAbS70T9S77_60_v.ttf';
    let customFont: PDFFont | undefined;
    try {
      const fontBytes = await fetch(fontUrl).then(res => {
        if (!res.ok) throw new Error(`?고듃 ?ㅼ슫濡쒕뱶 ?ㅽ뙣 (HTTP ${res.status})`);
        return res.arrayBuffer();
      });
      customFont = await mergedPdf.embedFont(fontBytes);
      console.log('PDF: Custom font loaded successfully');
    } catch (fontErr) {
      console.error('PDF: Custom font load failed:', fontErr);
    }

    // 媛?吏異??댁뿭??利앸튃 蹂묓빀
    for (const exp of expenditures) {
      if (!exp.attachmentUrl) continue;

      try {
        const response = await fetch(exp.attachmentUrl);
        if (!response.ok) throw new Error(`?뚯씪 ?ㅼ슫濡쒕뱶 ?ㅽ뙣 (HTTP ${response.status})`);

        const fileBytes = await response.arrayBuffer();
        const contentType = response.headers.get('content-type') || '';
        const fileName = exp.attachmentOriginalName || 'attachment.pdf';

        if (contentType.includes('pdf')) {
          const srcPdf = await PDFDocument.load(fileBytes);
          const srcPages = await mergedPdf.copyPages(srcPdf, srcPdf.getPageIndices());

          srcPages.forEach(page => {
            const { width, height } = page.getSize();

            // ?고듃媛 ?덈뒗 寃쎌슦?먮쭔 ?쒓? ?뚯씪紐?異쒕젰
            if (customFont) {
              const fontSize = 11;
              const textWidth = customFont.widthOfTextAtSize(fileName, fontSize);

              // ?곗륫 ?곷떒 ?뺣젹 (?щ갚 15, ?곷떒?먯꽌 15 ?대젮??
              // (0,0)? 醫뚯륫 ?섎떒?대?濡?height - offset ?ъ슜
              page.drawText(fileName, {
                x: width - textWidth - 25,
                y: height - 25,
                size: fontSize,
                font: customFont,
                color: rgb(0.2, 0.2, 0.2),
              });
            } else {
              // ?고듃 濡쒕뱶 ?ㅽ뙣 ???곷Ц?쇰줈?쇰룄 ?쒖떆 (?붾쾭源낆슜)
              page.drawText('Header Error: No Font', {
                x: width - 100,
                y: height - 25,
                size: 8,
                color: rgb(1, 0, 0),
              });
            }
            mergedPdf.addPage(page);
          });
        } else if (contentType.includes('image')) {
          // ?대?吏??jsPDF濡?PDF??????蹂묓빀
          const imgDoc = new jsPDF();
          const imgData = new Uint8Array(fileBytes);
          const imgProps = imgDoc.getImageProperties(imgData);
          const pdfWidth = imgDoc.internal.pageSize.getWidth();
          const pdfHeight = (imgProps.height * pdfWidth) / imgProps.width;

          imgDoc.addImage(imgData, (contentType.split('/')[1] || 'jpeg').toUpperCase(), 0, 0, pdfWidth, pdfHeight);
          const imgPdfBytes = imgDoc.output('arraybuffer');

          const imgPdf = await PDFDocument.load(imgPdfBytes);
          const [imgPage] = await mergedPdf.copyPages(imgPdf, [0]);

          const { width, height } = imgPage.getSize();
          if (customFont) {
            const fontSize = 11;
            const textWidth = customFont.widthOfTextAtSize(fileName, fontSize);

            imgPage.drawText(fileName, {
              x: width - textWidth - 25,
              y: height - 25,
              size: fontSize,
              font: customFont,
              color: rgb(0.2, 0.2, 0.2),
            });
          }
          mergedPdf.addPage(imgPage);
        }
      } catch (err: any) {
        console.error(`PDF: Failed to merge ${exp.attachmentOriginalName}:`, err);
      }
    }

    const pdfBytes = await mergedPdf.save();

    // ?ㅼ슫濡쒕뱶 ?몃━嫄?n    const blob = new Blob([new Uint8Array(pdfBytes)], { type: 'application/pdf' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `?쒖슱2026_利앸튃?⑹쿋_${executionName}_${new Date().getTime()}.pdf`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);

  } catch (err: any) {
    console.error('PDF Generation Error:', err);
    alert(`PDF ?앹꽦 以??ㅻ쪟媛 諛쒖깮?덉뒿?덈떎.\n?곸꽭?댁슜: ${err.message || '?????녿뒗 ?ㅻ쪟'}`);
  }
}

import { create } from 'zustand';
import { supabase } from '@/lib/supabase';

export interface MeetingAttendee {
  org: string;
  name: string;
}

export interface MeetingContent {
  title: string;
  detail: string;
}

export interface Meeting {
  id: string;
  title: string; // ?뚯쓽 ?쒕ぉ/?ъ뾽紐?吏곸젒 ?낅젰
  date: string;
  startTime: string;
  endTime: string;
  location: string;
  attendees: MeetingAttendee[];
  purpose: string;
  agenda: string;
  preparations: string;
  content: MeetingContent[];
  others: string;
  nextSchedule: string;
  projectId?: string;
  createdAt: number;
}

interface MeetingState {
  meetings: Meeting[];
  isLoading: boolean;

  // Actions
  fetchMeetings: () => Promise<void>;
  addMeeting: (meeting: Omit<Meeting, 'id' | 'createdAt'>) => Promise<void>;
  updateMeeting: (id: string, updates: Partial<Meeting>) => Promise<void>;
  deleteMeeting: (id: string) => Promise<void>;

  // Helpers
  getSortedMeetings: () => (Meeting & { sessionNumber: number })[];
}

export const useMeetingStore = create<MeetingState>((set, get) => ({
  meetings: [],
  isLoading: false,

  fetchMeetings: async () => {
    set({ isLoading: true });
    const { data, error } = await supabase
      .from('meetings')
      .select('*')
      .order('date', { ascending: true })
      .order('start_time', { ascending: true });

    if (error) {
      console.error('Error fetching meetings:', error);
    } else {
      const mapped: Meeting[] = (data || []).map(m => ({
        id: m.id,
        title: m.title || '',
        date: m.date,
        startTime: m.start_time || '',
        endTime: m.end_time || '',
        location: m.location || '',
        attendees: m.attendees || [],
        purpose: m.purpose || '',
        agenda: m.agenda || '',
        preparations: m.preparations || '',
        content: m.content || [],
        others: m.others || '',
        nextSchedule: m.next_schedule || '',
        projectId: m.project_id || undefined,
        createdAt: new Date(m.created_at).getTime(),
      }));
      set({ meetings: mapped });
    }
    set({ isLoading: false });
  },

  addMeeting: async (meetingData) => {
    const { error } = await supabase
      .from('meetings')
      .insert([{
        title: meetingData.title,
        date: meetingData.date,
        start_time: meetingData.startTime,
        end_time: meetingData.endTime,
        location: meetingData.location,
        attendees: meetingData.attendees,
        purpose: meetingData.purpose,
        agenda: meetingData.agenda,
        preparations: meetingData.preparations,
        content: meetingData.content,
        others: meetingData.others,
        next_schedule: meetingData.nextSchedule,
        project_id: meetingData.projectId,
      }]);

    if (error) {
      console.error('Add meeting error details:', error);
      throw error;
    }
    await get().fetchMeetings();
  },

  updateMeeting: async (id, updates) => {
    const updateData: any = {};
    if (updates.title !== undefined) updateData.title = updates.title;
    if (updates.date !== undefined) updateData.date = updates.date;
    if (updates.startTime !== undefined) updateData.start_time = updates.startTime;
    if (updates.endTime !== undefined) updateData.end_time = updates.endTime;
    if (updates.location !== undefined) updateData.location = updates.location;
    if (updates.attendees !== undefined) updateData.attendees = updates.attendees;
    if (updates.purpose !== undefined) updateData.purpose = updates.purpose;
    if (updates.agenda !== undefined) updateData.agenda = updates.agenda;
    if (updates.preparations !== undefined) updateData.preparations = updates.preparations;
    if (updates.content !== undefined) updateData.content = updates.content;
    if (updates.others !== undefined) updateData.others = updates.others;
    if (updates.nextSchedule !== undefined) updateData.next_schedule = updates.nextSchedule;
    if (updates.projectId !== undefined) updateData.project_id = updates.projectId;

    const { error } = await supabase
      .from('meetings')
      .update(updateData)
      .eq('id', id);

    if (error) throw error;
    await get().fetchMeetings();
  },

  deleteMeeting: async (id) => {
    const { error } = await supabase
      .from('meetings')
      .delete()
      .eq('id', id);

    if (error) throw error;
    await get().fetchMeetings();
  },

  getSortedMeetings: () => {
    const { meetings } = get();

    return [...meetings]
      .sort((a, b) => {
        if (a.date !== b.date) return a.date.localeCompare(b.date);
        return a.startTime.localeCompare(b.startTime);
      })
      .map((m, idx) => ({
        ...m,
        sessionNumber: idx + 1 // ?숈쟻 ?뚯감 遺??n      }));
  },
}));
